import pandas as pd
df = pd.DataFrame({"cliente_id": ["C001"], "region": ["Lima"]})
sub = df[df["cliente_id"] == "C001"]
if int(sub.duplicated(keep=False).sum()) >= 2:
    print("exact")
elif sub["region"].nunique() > 1:
    print("conflict")
else:
    print("clean")

